You are implementing Task 23: Automatic Notifications for a loyalty card app.

**Working directory:** C:\Users\User\loyalty-app

**What to create:**

### 1. Create `supabase/functions/auto-notifications/index.ts`

An Edge Function that runs daily and handles 3 types of automatic notifications:

1. **Inactivity** — Finds customer_cards where `last_activity` is > 14 days ago. Sends "We miss you!" push notification.
2. **Expiration warning** — Finds loyalty_programs with `expiration_days` set, and customer_cards whose points/stamps will expire within 7 days (created_at + expiration_days - 7 days < now). Sends expiration warning.
3. **Reward available** — Finds customer_cards where:
   - For stamp programs: `current_stamps >= stamp_goal`
   - For points programs: `current_points >= any reward's points_cost`
   Sends congratulation notification.

Each check deduplicates by checking if a notification of the same type was already sent to this customer within the last 24h.

```typescript
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
};

Deno.serve(async (req) => {
  if (req.method === 'OPTIONS') return new Response('ok', { headers: corsHeaders });

  try {
    const supabase = createClient(
      Deno.env.get('SUPABASE_URL')!,
      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!
    );

    const now = new Date();
    const oneDayAgo = new Date(now.getTime() - 24 * 60 * 60 * 1000).toISOString();
    const fourteenDaysAgo = new Date(now.getTime() - 14 * 24 * 60 * 60 * 1000).toISOString();
    let totalSent = 0;

    // 1. INACTIVITY REMINDERS
    const { data: inactiveCards } = await supabase
      .from('customer_cards')
      .select('id, customer_id, customers(push_token)')
      .lt('last_activity', fourteenDaysAgo);

    for (const card of inactiveCards ?? []) {
      const token = (card as any).customers?.push_token;
      if (!token) continue;

      // Dedup: check if already notified in last 24h
      const { count } = await supabase
        .from('notifications')
        .select('id', { count: 'exact', head: true })
        .eq('customer_id', card.customer_id)
        .eq('type', 'expiration_warning')
        .gte('sent_at', oneDayAgo);

      // Use a different type for inactivity - but our type constraint only allows specific types
      // We'll check for 'campaign' type notifications with a specific title as dedup
      if ((count ?? 0) > 0) continue;

      await fetch('https://exp.host/--/api/v2/push/send', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          to: token,
          title: 'We miss you!',
          body: 'Come back and check your loyalty rewards!',
        }),
      });

      await supabase.from('notifications').insert({
        customer_id: card.customer_id,
        title: 'We miss you!',
        body: 'Come back and check your loyalty rewards!',
        type: 'expiration_warning', // closest available type
        sent_at: now.toISOString(),
      });
      totalSent++;
    }

    // 2. EXPIRATION WARNING
    const { data: expiringCards } = await supabase
      .from('customer_cards')
      .select('id, customer_id, created_at, customers(push_token), loyalty_programs(expiration_days, name)')
      .not('loyalty_programs.expiration_days', 'is', null);

    for (const card of expiringCards ?? []) {
      const program = (card as any).loyalty_programs;
      if (!program?.expiration_days) continue;
      const token = (card as any).customers?.push_token;
      if (!token) continue;

      const expiresAt = new Date(new Date(card.created_at).getTime() + program.expiration_days * 24 * 60 * 60 * 1000);
      const daysUntilExpiry = (expiresAt.getTime() - now.getTime()) / (24 * 60 * 60 * 1000);
      if (daysUntilExpiry > 7 || daysUntilExpiry < 0) continue;

      const { count } = await supabase
        .from('notifications')
        .select('id', { count: 'exact', head: true })
        .eq('customer_id', card.customer_id)
        .eq('type', 'expiration_warning')
        .gte('sent_at', oneDayAgo);
      if ((count ?? 0) > 0) continue;

      await fetch('https://exp.host/--/api/v2/push/send', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          to: token,
          title: 'Points expiring soon!',
          body: `Your rewards at ${program.name} expire in ${Math.ceil(daysUntilExpiry)} days!`,
        }),
      });

      await supabase.from('notifications').insert({
        customer_id: card.customer_id,
        title: 'Points expiring soon!',
        body: `Your rewards at ${program.name} expire in ${Math.ceil(daysUntilExpiry)} days!`,
        type: 'expiration_warning',
        sent_at: now.toISOString(),
      });
      totalSent++;
    }

    // 3. REWARD AVAILABLE
    const { data: readyCards } = await supabase
      .from('customer_cards')
      .select('id, customer_id, current_stamps, current_points, customers(push_token), loyalty_programs(type, stamp_goal, name, id)')

    for (const card of readyCards ?? []) {
      const program = (card as any).loyalty_programs;
      const token = (card as any).customers?.push_token;
      if (!token || !program) continue;

      let eligible = false;
      if (program.type === 'stamp' && card.current_stamps >= program.stamp_goal) {
        eligible = true;
      } else if (program.type === 'points') {
        const { data: rewards } = await supabase
          .from('rewards')
          .select('points_cost')
          .eq('program_id', program.id)
          .lte('points_cost', card.current_points)
          .limit(1);
        if (rewards && rewards.length > 0) eligible = true;
      }

      if (!eligible) continue;

      const { count } = await supabase
        .from('notifications')
        .select('id', { count: 'exact', head: true })
        .eq('customer_id', card.customer_id)
        .eq('type', 'reward_available')
        .gte('sent_at', oneDayAgo);
      if ((count ?? 0) > 0) continue;

      await fetch('https://exp.host/--/api/v2/push/send', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          to: token,
          title: 'Reward available!',
          body: `You have enough to claim a reward at ${program.name}!`,
        }),
      });

      await supabase.from('notifications').insert({
        customer_id: card.customer_id,
        title: 'Reward available!',
        body: `You have enough to claim a reward at ${program.name}!`,
        type: 'reward_available',
        sent_at: now.toISOString(),
      });
      totalSent++;
    }

    return new Response(JSON.stringify({ sent: totalSent }), {
      status: 200,
      headers: { ...corsHeaders, 'Content-Type': 'application/json' },
    });
  } catch (err) {
    return new Response(JSON.stringify({ error: (err as Error).message }), { status: 500, headers: corsHeaders });
  }
});
```

### 2. Create `supabase/migrations/006_cron_auto_notif.sql`

NOTE: pg_cron and pg_net may not be available in all environments (they require Supabase Pro plan). Create the migration with a comment noting this:

```sql
-- Requires pg_cron and pg_net extensions (available on Supabase Pro plan)
-- Enable extensions
create extension if not exists pg_cron;
create extension if not exists pg_net;

-- Schedule auto-notifications to run daily at 10:00 UTC
select cron.schedule(
  'auto-notifications',
  '0 10 * * *',
  $$select net.http_post(
    url := current_setting('app.supabase_url') || '/functions/v1/auto-notifications',
    headers := jsonb_build_object('Authorization', 'Bearer ' || current_setting('app.service_role_key')),
    body := '{}'::jsonb
  )$$
);
```

### 3. Commit

```bash
git add .
git commit -m "feat: add automatic notifications with cron scheduling"
```

**Important:**
- Do NOT skip the commit step
- Follow the existing Edge Function patterns (CORS headers, error handling, etc.)

